import React, { useState, useMemo, useCallback } from 'react';
import { useQuery } from 'convex/react';
import { api } from '../../../convex/_generated/api';
import { WorkProps } from '../../../types';
import PageNavigation from '../PageNavigation/PageNavigation';
import { getTranslations, interpolate } from '../../../i18n';

import './Portfolio.css';

const CATEGORIES = ['all', 'professional', 'web3', 'experiments'] as const;

const Portfolio: React.FC<WorkProps> = ({ setDialogText, setCurrentAction, lang }) => {
  const t = getTranslations(lang);
  const projects = useQuery(api.projects.list);
  const [activeCategory, setActiveCategory] = useState('all');

  const filteredProjects = useMemo(
    () =>
      activeCategory === 'all'
        ? projects ?? []
        : (projects ?? []).filter((p) => p.category === activeCategory),
    [activeCategory, projects]
  );

  const handleCategoryClick = useCallback((category: string) => {
    setActiveCategory(category);
  }, []);

  if (projects === undefined) {
    return (
      <div id="portfolio" className="retro-page">
        <PageNavigation currentSection="goTo-portfolio" onNavigate={setCurrentAction} lang={lang} />
        <div className="page-content">
          <h1 className="portfolio-title">{t.portfolio.title}</h1>
          <div className="project-info" style={{ textAlign: 'center', padding: '40px' }}>
            <i className="spinner icon"></i>
            <p>{t.portfolio.loadingProjects}</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div id="portfolio" className="retro-page">
      <PageNavigation currentSection="goTo-portfolio" onNavigate={setCurrentAction} lang={lang} />

      <div className="page-content">
        <h1 className="portfolio-title">{t.portfolio.title}</h1>

        <div className="retro-box" style={{ textAlign: 'center', marginBottom: '20px' }}>
          {t.portfolio.clickToView}
        </div>

        {/* Category Tabs */}
        <div className="portfolio-category-tabs category-tabs">
          {CATEGORIES.map((cat) => (
            <div
              key={cat}
              className={`category-tab ${activeCategory === cat ? 'active' : ''}`}
              onClick={() => handleCategoryClick(cat)}
            >
              {t.portfolio.categories[cat]}
            </div>
          ))}
        </div>

        {filteredProjects.length === 0 ? (
          <div className="project-info" style={{ textAlign: 'center', padding: '40px' }}>
            <p>{t.portfolio.noProjects}</p>
          </div>
        ) : (
          <div className="portfolio-grid">
            {filteredProjects.map((project) => (
              <div key={project._id} className="portfolio-card">
                <div className="project-image">
                  <a href={project.url} target="_blank" rel="noreferrer" title={project.name}>
                    <img src={project.image} alt={project.name} loading="lazy" />
                  </a>
                </div>
                <div className="project-info">
                  <a href={project.url} target="_blank" rel="noreferrer" title={project.name}>
                    <h2>{project.name}</h2>
                  </a>
                  <p>{project.description}</p>
                  {project.url && (
                    <button
                      className="retro-button primary"
                      onClick={() => window.open(project.url, '_blank', 'noreferrer')}
                      title={project.name}
                    >
                      {t.portfolio.visitProject}
                    </button>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}

        <div style={{ textAlign: 'center', marginTop: '30px' }}>
          <div className="visitor-counter" style={{ margin: '0 auto 20px', display: 'table' }}>
            {interpolate(t.portfolio.projectsAvailable, { count: projects.length })}
          </div>
          <button
            className="retro-button primary"
            onClick={() => {
              if (setCurrentAction) {
                setCurrentAction('goTo-contact');
                if (setDialogText) {
                  setDialogText(t.portfolio.loveToHear);
                }
              }
            }}
          >
            {t.portfolio.getInTouch}
          </button>
        </div>
      </div>
    </div>
  );
};

export default Portfolio;
